Javascript.miscCode:
		 
			PartiesFailedToFile.srcData = DATA_XPATH + "/Parties";
			PartiesFailedToFile.rowXPath = "*[./Status != 'REMOVED']";	
			
			PartiesFailedToFile.keyXPath = "PartyId";
			PartiesFailedToFile.columns = [
				{xpath: "Type"},
				{xpath: "Number", sort: "numerical", defaultSort:"true", defaultSortOrder:"ascending"},
				{xpath: "Name"}
			];
			PartiesFailedToFile.multipleSelection = true;	
		
			// Since PartiesFailedToFile is a multi-select grid and grids do not implement mandatory protocol, we need to
			// use some other field in the same group as this question to be defined in the validateOn xpaths. 
			// OrderDetails2 here has become one such possible candidate since it is itseld a mandatory field.
			
			PartiesFailedToFile.validateOn = [PartiesFailedToFile.dataBinding + "/PartyId", OrderDetails2.dataBinding];
			PartiesFailedToFile.validate = function()
			{ 
				var ec = null;
				var countParties = Services.countNodes(PartiesFailedToFile.dataBinding + "/PartyId");
				if (countParties == 0)
				{
					ec = ErrorCode.getErrorCode("CaseMan_AtLeastOnePartyMustBeSelected");
				}
				return ec;
			 }	
